#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res(0);char ch(getchar());while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void rd(bool &Q){char ch;do ch=getchar();while(ch!='1'&&ch!='0');Q=ch=='1';}
const int N=310;const LL INF=1e15;LL dp[N][N][256];int w[256],n,K;bool c[256],s[N];
inline int Len(const int &l,const int &r){int qwq=(r-l)%(K-1);return qwq?qwq:K-1;}
inline void chkmax(LL &x,const LL &w){x<w?x=w:0ll;}
int main()
{
	n=read();K=read();rep(1,n,i)rd(s[i]);
	for(int i=0;i<(1<<K);++i)rd(c[i]),w[i]=read();
	memset(dp,-0x3f,sizeof(dp));LL ans=-INF;
	rep(1,n,T)for(int l=1,r=T;r<=n;++l,++r)
	{
		
		if(l==r){dp[l][r][s[l]]=0;continue;}int len=Len(l,r);
		for(int k=r;k>l;k-=K-1)for(int S=0;S<(1<<len);++S)
		{
			chkmax(dp[l][r][S<<1],dp[l][k-1][S]+dp[k][r][0]);
			chkmax(dp[l][r][S<<1|1],dp[l][k-1][S]+dp[k][r][1]);
		}
		if(len==K-1)
		{
			LL tmp[2]={-INF,-INF};
			for(int S=0;S<(1<<K);++S)chkmax(tmp[c[S]],dp[l][r][S]+w[S]);
			dp[l][r][0]=tmp[0];dp[l][r][1]=tmp[1];
		}
//		printf("(%d,%d) :: ",l,r);rep(0,(1<<K)-1,i)printf("%lld ",dp[l][r][i]);puts("");
	}
	for(int S=0;S<(1<<K);++S)chkmax(ans,dp[1][n][S]);printf("%lld\n",ans);return 0;
}
